(async () => {
  const INITIAL_PAGE_LOAD_DELAY = 3000;  // ms: wait for SPA render
  const SCROLL_DELAY = 1500;             // ms: wait after each scroll step
  const MAX_SCROLL_ITERATIONS = 100;     // safety cap for very large playlists
  const MAX_SCROLL_DURATION_MS = 120000; // 2-minute wall-clock timeout

  await new Promise(r => setTimeout(r, INITIAL_PAGE_LOAD_DELAY));

  // Scroll until no new items load or the time limit is reached.
  // Do NOT break early when count is still 0 - the page may still be rendering.
  let prevCount = 0;
  const scrollStart = Date.now();
  for (let i = 0; i < MAX_SCROLL_ITERATIONS; i++) {
    if (Date.now() - scrollStart > MAX_SCROLL_DURATION_MS) break;
    const items = document.querySelectorAll('ytd-playlist-video-renderer');
    if (items.length > 0 && items.length === prevCount) break;
    prevCount = items.length;
    window.scrollTo(0, document.documentElement.scrollHeight);
    await new Promise(r => setTimeout(r, SCROLL_DELAY));
  }

  window.scrollTo(0, 0);

  // Try multiple selectors for the playlist title (YouTube occasionally updates the DOM)
  const titleEl = document.querySelector(
    'h1.ytd-playlist-header-renderer yt-formatted-string, ' +
    'ytd-playlist-header-renderer h1, ' +
    'yt-formatted-string#title, ' +
    '#title.ytd-playlist-header-renderer'
  );
  const playlistTitle = (titleEl ? titleEl.textContent.trim() : 'playlist')
    .replace(/[\/:\*\?"<>|]/g, '_');

  const videoItems = document.querySelectorAll('ytd-playlist-video-renderer');
  const lines = [];

  videoItems.forEach(item => {
    const linkEl = item.querySelector('a#video-title');
    if (linkEl) {
      const title = linkEl.textContent.trim();
      const href = linkEl.getAttribute('href');
      if (title && href) {
        lines.push('- [' + title + '](https://www.youtube.com' + href + ')');
      }
    }
  });

  if (lines.length === 0) {
    automaNextBlock({ message: '動画が見つかりませんでした' });
    return;
  }

  const markdown = lines.join('\n') + '\n';

  // Use data: URI for reliable download across all execution contexts
  const dataUri = 'data:text/plain;charset=utf-8,' + encodeURIComponent(markdown);
  const a = document.createElement('a');
  a.setAttribute('href', dataUri);
  a.setAttribute('download', playlistTitle + '.md');
  a.style.display = 'none';
  document.body.appendChild(a);
  a.click();
  document.body.removeChild(a);

  automaNextBlock({ message: 'Downloaded: ' + playlistTitle + '.md (' + lines.length + ' videos)' });
})()
